"use client";

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
    Card,
    CardAction,
    CardDescription,
    CardFooter,
    CardHeader,
    CardTitle,
} from "@/components/ui/card"

const ProductCard = (props) => {
    const formattedPrice = new Intl.NumberFormat('zh-TW', {
        style: 'currency',
        currency: 'TWD',
        minimumFractionDigits: 0
    }).format(props.price);


    // todo: 將點擊加入購物
    // const handleAddClick = () => {
    //     const productToAdd = {
    //         id: props.id,             // 統一用 id
    //         name: props.name,         // 統一用 name
    //         price: props.price,
    //         image: props.image,       // 統一用 image
    //         quantity: props.quantity  // 統一用 quantity
    //     };
    // };

    return (
        <div className="group cursor-pointer bg-white/30 p-3 rounded-[24px] border border-white/50 transition-all duration-300 hover:bg-white/60 hover:shadow-2xl hover:-translate-y-2">

            {/* 圖片區域 */}
            <div className="relative aspect-[3/2] overflow-hidden rounded-retro shadow-inner">
                <Image
                    src={props.image}
                    alt={props.name}
                    fill
                    className="object-cover transition-transform duration-700 group-hover:scale-105"
                />

                {/* 分類標籤 (Category Badge) */}
                <span className="absolute top-3 left-3 px-3 py-1 bg-retro-bg/90 backdrop-blur-sm text-retro-ink text-[10px] font-bold uppercase tracking-widest rounded-full shadow-sm">
                    {props.category}
                </span>
            </div>

            {/* 商品資訊區塊 */}
            <div className="mt-4 px-1 flex flex-col gap-1">
                <div className="flex justify-between items-start">
                    <div>
                        <h3 className="text-retro-ink font-bold text-base tracking-tight">{props.name}</h3>
                        <p className="text-retro-slate text-sm font-medium">{formattedPrice}</p>
                    </div>
                </div>

                {/* 加入購物車按鈕：膠囊風格 */}
                <button
                    className="mt-3 w-full py-2.5 rounded-full bg-retro-ink text-retro-bg text-sm font-bold transition-all duration-300 hover:bg-retro-ink/90 active:scale-95 shadow-md"
                /* onClick={handleAddClick} */
                >
                    加入購物車
                </button>
            </div>
        </div>
    );
};

export default ProductCard;